use std::fmt::Display;

pub trait Licensed {
    fn licensing_info(&self) -> String {
        "Default license".to_string()
    }
}

struct SomeSoftware;
struct OtherSoftware;

impl Licensed for SomeSoftware {}
impl Licensed for OtherSoftware {
    fn licensing_info(&self) -> String {
        "OtherSoftware License v2".to_string()
    }
}

fn compare_license_types(software: &impl Licensed, software2: &impl Licensed) -> bool {
    software.licensing_info() == software2.licensing_info()
}

fn main() {
    let s1 = SomeSoftware;
    let s2 = OtherSoftware;
    println!("Same license? {}", compare_license_types(&s1, &s2));
}
